const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

const publicKey = 'YOUR_PUBLIC_KEY'; // Public key of the authorization server

// Middleware for validating the access token in the authorization header
app.use((req, res, next) => {
  const authHeader = req.headers.authorization;
  
  if (authHeader) {
    const token = authHeader.split(' ')[1]; // Bearer <Access-Token>

    jwt.verify(token, publicKey, (err, user) => {
      if (err) {
        return res.sendStatus(403);
      }

      req.user = user;
      next();
    });
  } else {
    res.sendStatus(401);
  }
});

app.get('/resource', (req, res) => {

  // A protected resource
  res.send('Access granted to protected resource!');

});

app.listen(3000, () => console.log('Server started on port 3000'));